struct RegisterContext // 通用寄存器的上下文
{
    union // 使用联合体，这样既可以按名字访问寄存器，也可以按编号访问寄存器
    {
        RegisterData x[32];
        struct // 按照Risc-V64规范定义的32个寄存器
        {
            RegisterData zero,
                ra, sp, gp, tp,
                t0, t1, t2,
                s0, s1,
                a0, a1, a2, a3, a4, a5, a6, a7,
                s2, s3, s4, s5, s6, s7, s8, s9, s10, s11,
                t3, t4, t5, t6;
        };
    };

    inline RegisterData& operator[](int index)
    {
        return x[index];
    }
};

